var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"베일!!!","JPN":"ベイル！！！","ENG":"Vale!","TWN":"培麗！！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"들리면 어서 대답하게!","JPN":"聞こえているなら返事したまえ！","ENG":"Answer me if you can hear me, now!","TWN":"有聽到嗎？快回答我！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>…</color>","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_15"},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"베일…?","JPN":"ベイル……？","ENG":"Vale…?","TWN":"培麗…？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"악몽을 꾼다고요?","JPN":"悪夢を見る？","ENG":"You've been having nightmares?","TWN":"你說你做惡夢？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"별일 아니니 걱정 마시게. 이런 경험은 익숙하니.","JPN":"大したことではないから心配はいらん。こういうのには慣れているゆえ。","ENG":"It's nothing worth fretting over. I've grown quite used to such things.","TWN":"這沒什麼，你不用擔心。我已經習慣做惡夢。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"잠에서 깰 때마다 숨이 갑갑하다면서요? 그게 어떻게 별일이 아녜요?","JPN":"目覚めるたびに息が苦しいんでしょう？　それのどこが大したことじゃないんですか。","ENG":"You said you wake up feeling like you can't breathe. How's that nothing worth fretting over?","TWN":"你不是說每次醒來都覺得呼吸困難？這怎麼會是沒什麼？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"똑같은 경험은 아니겠지만… 나도 악몽을 자주 꾸곤 했어요.","JPN":"まったく同じとは言えませんけど……私もよく悪夢に苛まれていました。","ENG":"It's not quite the same, but… I used to have nightmares too.","TWN":"雖然跟你的經歷不太一樣…但我以前也經常做惡夢。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"대학시절에 침식재난에 휘말렸는데, 그때 내가 미처 구하지 못한 친구들이 계속 꿈에 나오거든요.","JPN":"大学時代、侵食災害に巻き込まれて。あの時、助けられなかった友人たちが夢に出てくるんです。","ENG":"Back in college, I got caught up in a Corruption disaster. The friends I couldn't save back then… they still come back in my dreams.","TWN":"大學時遇到侵蝕災難，那時候我沒能救活的朋友們會一直在夢裡出現。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"마음이 편치 않았겠구려.","JPN":"それは大変な思いをしたな。","ENG":"That must weigh heavily on you.","TWN":"你心裡一定很不好受吧。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"안타깝지만 그대는 평범한 사람이지 않은가. 관리국조차 침식재난 같은 재앙으로부터 모두를 구할 순 없는 걸세.","JPN":"しかし、残念だがそなたは普通の人間だ。管理局ですら侵食災害のような災害からは万人を救うことなどできん。","ENG":"Yet you're only an ordinary human, Vale. Not even the Administration could save everyone from a Corruption disaster.","TWN":"雖然很遺憾，但你只是一個普通人。就連管理局也無法從侵蝕災難這種災難中拯救所有人。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그 말이 맞아요. 그래서 악몽을 꾼 날은 무작정 바이크를 타고 정처 없이 달리곤 하죠.","JPN":"その通りです。だから悪夢を見た日は、バイクに乗ってあてもなく走るんです。","ENG":"You're right. So whenever I wake from one of those nightmares, I just jump on my bike and ride with no destination in mind.","TWN":"你說得對。所以每次做惡夢，我都會騎著摩托車漫無目的地狂奔。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"거리의 바람을 쐬면 잠깐동안 숨통이 트이긴 하지만… 결국 내가 아무것도 할 수 없다는 무력감을 지울 순 없더라고요.","JPN":"街の風に当たると、少しの間気が楽になるけど……結局、私には何もできないという無力感を消し去ることはできないんですよね。","ENG":"The wind on the road clears my head for a while… But that helpless feeling always creeps back in.","TWN":"雖然吹著街上的風，暫時能喘口氣…但那種無能為力的無奈感，終究無法抹去。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"지울 수 없다면, 우리가 할 수 있는 일을 해보는 건 어떻겠소?","JPN":"消せないのなら、我らにできることをしたらどうだろうか。","ENG":"If we can't erase it… then why not do what we can, instead?","TWN":"如果無法抹去，那不如試著做我們能做的事如何？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"네…?","JPN":"え……？","ENG":"Huh…?","TWN":"嗯…？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대는 어린 시절에 보던 봄꽃이 그립다고 했었지.","JPN":"そなたは幼少期に見た春の花が恋しいと言っていたな。","ENG":"You once told me you missed the spring blossoms you used to see as a child.","TWN":"你說你懷念小時候看過的春天花朵對吧。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아, 그런 얘기도 했었죠. 대정화전쟁 이후론 이젠 볼 수 없는 풍경이 되어버렸지만요.","JPN":"あ、そういう話もしましたね。大浄化戦争の後、二度と見られない景色になってしまったけど。","ENG":"Ah, I did say that. After the Grand Purification War, that kind of scenery just vanished.","TWN":"對欸，我跟你說過。不過大淨化戰爭後，就再也看不到了。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그렇다면 우리가 잃어버린 계절을 되찾아보는 걸세.","JPN":"それなら、失われた季節を我らの手で取り戻すのだ。","ENG":"Then perhaps, we might try bringing that lost season back.","TWN":"既然如此，我們就把那失落的季節找回來吧。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대는 챔버의 학자라네. 이미 지난 일을 돌이키진 못해도, 세상을 침식으로부터 좀 더 살기 좋은 곳으로 바꿀 순 있을 거야.","JPN":"そなたはチェンバーの学者である。起きてしまったことをなかったことにはできぬが、世界をより良くすることならできるはずだ。","ENG":"You're a scholar of Chamber, Vale. We cannot undo what's past, but we might yet make this world a better place, free of Corruption.","TWN":"你是強巴的學者。雖然無法挽回過去的事，但至少能讓這個世界變得更適合居住。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"하지만… 계절을 되찾는다니. 현실적으로 불가능하지 않나요?","JPN":"でも……季節を取り戻すって、現実的に無理じゃないですか？","ENG":"But… bringing back the seasons? Isn't that impossible?","TWN":"但是…找回季節？這在現實中是不可能的吧？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이곳 챔버엔 무궁무진한 가능성이 있지.","JPN":"ここ、チェンバーは無限大の可能性を秘めている。","ENG":"Here in Chamber, there's no shortage of potential.","TWN":"強巴有著無窮無盡的可能性。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"다 함께 머리를 맞댄다면 시도할 가치는 있지 않겠나?","JPN":"皆で力を合わせれば、試す価値はあるのではないか？","ENG":"If we all put our heads together, surely, it's worth the attempt.","TWN":"若大家集思廣益，這件事還是值得一試的吧？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"하하…","JPN":"はは……","ENG":"Haha…","TWN":"哈哈…"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"서생 씨가 자신 있게 말하니까 진짜로 될 것 같아요.","JPN":"ショウさんにそこまで自信満々に言われると、本当にできる気がしてきました。","ENG":"When you say it like that, it almost sounds like it might really happen.","TWN":"看你說得一副信誓旦旦的樣子，好像真的會成功一樣。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"원래 고민을 들어주려고 했던 건데, 오히려 제가 도움을 받은 기분이네요.","JPN":"悩みを聞いてあげるつもりだったのに、逆に助けられてしまいましたね。","ENG":"I was supposed to be the one comforting you. Yet here I am, the one feeling better.","TWN":"本來是想聽你傾訴煩惱的，結果反而是我被安慰呢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"답례로 제가 해드릴 만한 게 있을까요?","JPN":"お礼に、私から何かできることはないですか？","ENG":"Is there anything I can do to return the favor?","TWN":"我可以做點什麼報答你嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대가 타고 다니는 바이크. 나도 배우고 싶구려.","JPN":"そなたが乗っているそのバイクを、某にも教えてくれぬか。","ENG":"Your motorbike. I'd like to learn how to ride.","TWN":"我也想學騎摩托車。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"원래 관심이 있었어요?","JPN":"興味があったんですか？","ENG":"You were interested in riding?","TWN":"你本來就對摩托車有興趣嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"달리면서 바람을 쐬다 보면, 가슴이 답답할 때 도움이 되지 않을까 싶어서 말이요.","JPN":"乗って風に当たれば、落ち着かない時に役に立つかと思ってな。","ENG":"I thought, perhaps riding through the wind might ease my chest when it grows heavy.","TWN":"當心情鬱悶時，騎車兜風或許能有所幫助。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그럼요. 얼마든지 가르쳐줄게요.","JPN":"もちろんです。いくらでも教えますよ。","ENG":"Sure. I'll teach you anytime.","TWN":"當然可以。我隨時都可以教你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"너무 뒤쳐지진 말아요.","JPN":"その代わり、遅れ過ぎないでくださいね。","ENG":"Just don't fall too far behind.","TWN":"不過別落後太多。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"오래 기다리게 하면 안 기다려주고 갈 거니까.","JPN":"あまり待たせると置いて行っちゃいますよ。","ENG":"I won't be waiting for you for too long.","TWN":"如果讓我等太久，我會直接騎走不管你的喔。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"어제의 친구가 오늘 생기 없는 눈과 이빨을 드러내며 날 노려본다는 건… 참으로 잔인한 경험일세.","JPN":"昨日の友が、今日は目の光を失い牙をむいて睨んでくるというのは……何とも残酷なものである。","ENG":"To have a friend from yesterday glare at me today with lifeless eyes and bared teeth… It's a truly cruel experience.","TWN":"昨天的朋友，今天卻眼神空洞，張牙舞爪地瞪著我…這真是殘酷的經驗。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"꿈인가 싶어 감았던 눈을 부릅뜨지만, 현실만이 더욱 선명해질 뿐이지.","JPN":"夢かと思い、一瞬閉じた瞼を再び見開くものの、現実はより鮮明になるのみ。","ENG":"I squeeze my eyes shut, hoping it's a dream. But when I open them, reality only sharpens.","TWN":"我本以為這是一場夢，但睜大眼後，現實卻變得更加清晰。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"일순 누군가 떨어트린 총 한 자루에 시선이 갔으나, 난 조용히 발걸음을 돌렸네.","JPN":"一瞬、誰かの落とした1丁の銃に目が留まったが、某はそのまま静かに踵を返した。","ENG":"For a moment, my gaze fell on a gun someone had dropped, but I quietly turned away.","TWN":"我的視線掃向某人丟下的槍，卻默默地轉過身。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"그제서야 뒤늦게 눈에 들어오더군. 날 바닥에 널브러진 피투성이 시신들.","JPN":"その時になってようやく目に入ってきたのだ。血まみれになり床に転がっている複数の死体に。","ENG":"Only then did I notice the bodies sprawled across the floor, soaked in blood.","TWN":"這時我才看到，地上躺著血淋淋的屍體。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"그 피는 내 친구의 날카롭고 검은 손아귀에서 뚝뚝 떨어지던 것과 같은 색이었지.","JPN":"その血は、我が友の鋭く黒い手からぽたぽたと落ちるものと同じ色をしていた。","ENG":"Blood of the same color that dripped from my friend's black, jagged claws.","TWN":"那鮮血，和我朋友那雙鋒利、黝黑的手滴下的顏色一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…작별이 투박하여 미안하네, 베일.","JPN":"……こんな素っ気ない別れ方ですまない、ベイル。","ENG":"…Forgive my clumsy goodbye, Vale.","TWN":"…培麗抱歉，沒能風光地送你走。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"때가 되면…","JPN":"きっと、いつの日か……","ENG":"When the time comes…","TWN":"我們…"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"우리 다시 만나지.","JPN":"また会える時が来る。","ENG":"We shall meet again.","TWN":"後會有期。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};